import logo from './logo.svg';
import './App.css';
import { useState } from 'react';

function App() {
  [dice, setDice] = useState(0)
  function clickHandler(){
	setDice(Math.floor(Math.random() * 5 + 1))
  }
  return (
    <div className="App">
		<div onClick={clickHandler}></div>
		<img src={`${dice}.png`}></img>
    </div>
  );
}

export default App;
